package agentd

import (
	"context"
	"fmt"
	"time"

	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/types"
	ctrl "sigs.k8s.io/controller-runtime"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/log"

	sandboxv1alpha1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
)

const (
	SessionExpirationTimeout  = 15 * time.Minute
	LastActivityAnnotationKey = "last-activity-time"
)

type SandboxReconciler struct {
	client.Client
	Scheme *runtime.Scheme
}

func (r *SandboxReconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	logger := log.FromContext(ctx)

	sandbox := &sandboxv1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if errors.IsNotFound(err) {
			logger.Info("Sandbox not found, skipping")
			return ctrl.Result{}, nil
		}
		logger.Error(err, "Failed to get sandbox")
		return ctrl.Result{}, err
	}

	annotation := sandbox.Annotations[LastActivityAnnotationKey]
	if annotation == "" {
		logger.Info("No last-activity annotation, skipping idle cleanup")
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, annotation)
	if err != nil {
		logger.Error(err, "Failed to parse last-activity annotation", "annotation", annotation)
		return ctrl.Result{RequeueAfter: 30 * time.Second}, err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expirationTime) {
		logger.Info("Sandbox idle beyond expiration, deleting", "lastActivity", lastActivity, "expiration", expirationTime)

		if err := r.Delete(ctx, sandbox); err != nil {
			if errors.IsNotFound(err) {
				logger.Info("Sandbox already deleted")
				return ctrl.Result{}, nil
			}
			logger.Error(err, "Failed to delete sandbox")
			return ctrl.Result{}, err
		}

		logger.Info("Successfully deleted idle sandbox")
		return ctrl.Result{}, nil
	}

	requeueAfter := time.Until(expirationTime)
	logger.Info("Sandbox not yet expired, requeueing", "requeueAfter", requeueAfter)
	return ctrl.Result{RequeueAfter: requeueAfter}, nil
}

func (r *SandboxReconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&sandboxv1alpha1.Sandbox{}).
		Complete(r)
}

