	if err := s.storeClient.UpdateSessionLastActivity(ctx, sandbox.SessionID, time.Now()); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: failed to update last activity: %v\n", err)
	}

	upstreamURL, err := s.determineUpstreamURL(sandbox, path)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	proxy.Transport = s.httpTransport
	proxy.ErrorHandler = s.proxyErrorHandler
	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = upstreamURL.Scheme
		req.URL.Host = upstreamURL.Host
		req.URL.Path = s.normalizePath(path)
		req.URL.RawPath = ""
		req.Host = upstreamURL.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		if xff := req.Header.Get("X-Forwarded-For"); xff != "" {
			req.Header.Set("X-Forwarded-For", xff+", "+c.ClientIP())
		} else {
			req.Header.Set("X-Forwarded-For", c.ClientIP())
		}

		if kind == types.SandboxKind || kind == types.SandboxClaimsKind {
			claims := map[string]interface{}{
				"session_id": sandbox.SessionID,
			}
			token, err := s.jwtManager.GenerateToken(claims)
			if err != nil {
				fmt.Fprintf(os.Stderr, "Warning: failed to generate JWT: %v\n", err)
				return
			}
			req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandbox.SessionID)
		return nil
	}

	proxy.ServeHTTP(c.Writer, c.Request)

	if err := s.storeClient.UpdateSessionLastActivity(ctx, sandbox.SessionID, time.Now()); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: failed to update last activity: %v\n", err)
	}
}

func (s *Server) determineUpstreamURL(sandbox *types.SandboxInfo, path string) (*url.URL, error) {
	if len(sandbox.EntryPoints) == 0 {
		return nil, fmt.Errorf("no entry point found for sandbox")
	}

	var matchedEntry *types.SandboxEntryPoint
	for i, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			matchedEntry = &sandbox.EntryPoints[i]
			break
		}
	}

	if matchedEntry == nil {
		matchedEntry = &sandbox.EntryPoints[0]
	}

	endpoint := matchedEntry.Endpoint
	if matchedEntry.Protocol != "" && !strings.HasPrefix(endpoint, "http://") && !strings.HasPrefix(endpoint, "https://") {
		endpoint = fmt.Sprintf("%s://%s", strings.ToLower(string(matchedEntry.Protocol)), endpoint)
	}

	return url.Parse(endpoint)
}

func (s *Server) normalizePath(path string) string {
	if path == "" {
		return "/"
	}
	if !strings.HasPrefix(path, "/") {
		return "/" + path
	}
	return path
}

func (s *Server) proxyErrorHandler(w http.ResponseWriter, r *http.Request, err error) {
	errMsg := err.Error()
	if strings.Contains(errMsg, "connection refused") || strings.Contains(errMsg, "no such host") {
		w.WriteHeader(http.StatusBadGateway)
		w.Write([]byte(`{"error":"sandbox unreachable"}`))
	} else if strings.Contains(errMsg, "timeout") || strings.Contains(errMsg, "deadline exceeded") {
		w.WriteHeader(http.StatusGatewayTimeout)
		w.Write([]byte(`{"error":"sandbox timeout"}`))
	} else {
		w.WriteHeader(http.StatusBadGateway)
		w.Write([]byte(`{"error":"sandbox unreachable"}`))
	}
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	if apiErr, ok := err.(apierrors.APIStatus); ok {
		status := apiErr.Status()
		code := int(status.Code)
		if code == 0 {
			code = http.StatusInternalServerError
		}
		message := status.Message
		if message == "" {
			message = err.Error()
		}
		if code == http.StatusInternalServerError {
			message = "internal server error"
		}
		c.JSON(code, gin.H{"error": message})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (s *Server) Start() error {
	addr := ":" + s.config.Port

	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           h2c.NewHandler(s.engine, &http2.Server{}),
		ReadTimeout:       30 * time.Second,
		IdleTimeout:       90 * time.Second,
		ReadHeaderTimeout: 10 * time.Second,
	}

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return fmt.Errorf("TLS is enabled but cert or key path not provided")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	var shutdownErr error
	var wg sync.WaitGroup

	wg.Add(1)
	go func() {
		defer wg.Done()
		shutdownErr = s.httpServer.Shutdown(ctx)
	}()

	wg.Wait()
	return shutdownErr
}

