type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

type SessionManager interface {
	GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*store.SandboxInfo, error)
}

type manager struct {
	storeClient     store.Store
	workloadMgrAddr string
	httpClient      *http.Client
}

func NewServer(config *Config, sessionManager SessionManager) (*Server, error) {
	if config.Debug {
		gin.SetMode(gin.DebugMode)
	} else {
		gin.SetMode(gin.ReleaseMode)
	}

	engine := gin.New()

	httpTransport := &http.Transport{
		DisableCompression:    false,
		MaxIdleConnsPerHost:   100,
		MaxConnsPerHost:       0,
		TLSHandshakeTimeout:   10 * time.Second,
		ExpectContinueTimeout: 1 * time.Second,
		IdleConnTimeout:       90 * time.Second,
	}

	if err := http2.ConfigureTransport(httpTransport); err != nil {
		return nil, fmt.Errorf("failed to configure HTTP/2 transport: %w", err)
	}

	jwtManager := NewJWTManager()
	if err := jwtManager.TryStoreOrLoadJWTKeySecret(context.Background()); err != nil {
		return nil, fmt.Errorf("failed to initialize JWT key secret: %w", err)
	}

	storeClient := store.Storage()

	s := &Server{
		config:         config,
		engine:         engine,
		sessionManager: sessionManager,
		storeClient:    storeClient,
		httpTransport:  httpTransport,
		jwtManager:     jwtManager,
	}

	s.setupRoutes()

	return s, nil
}

func NewJWTManager() *JWTManager {
	privateKey, err := rsa.GenerateKey(rand.Reader, rsaKeySize)
	if err != nil {
		return &JWTManager{}
	}
	return &JWTManager{
		privateKey: privateKey,
		publicKey:  &privateKey.PublicKey,
	}
}

func (j *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	if j.clientset == nil {
		config, err := rest.InClusterConfig()
		if err != nil {
			return fmt.Errorf("failed to get in-cluster config: %w", err)
		}
		j.clientset, err = kubernetes.NewForConfig(config)
		if err != nil {
			return fmt.Errorf("failed to create kubernetes client: %w", err)
		}
	}

	privateKeyPEM, publicKeyPEM := j.generateKeyPair()

	secret := &v1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: IdentityNamespace,
			Labels: map[string]string{
				"app":       "agentcube",
				"component": "router",
			},
		},
		Type: v1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: []byte(privateKeyPEM),
			PublicKeyDataKey:  []byte(publicKeyPEM),
		},
	}

	_, err := j.clientset.CoreV1().Secrets(IdentityNamespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		if !apierrors.IsAlreadyExists(err) {
			return fmt.Errorf("failed to create secret: %w", err)
		}
		existing, err := j.clientset.CoreV1().Secrets(IdentityNamespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
		if err != nil {
			return fmt.Errorf("failed to get existing secret: %w", err)
		}
		return j.loadPrivateKeyPEM(string(existing.Data[PrivateKeyDataKey]))
	}

	return nil
}

func (j *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	now := time.Now()
	tokenClaims := jwt.MapClaims{
		"exp": now.Add(jwtExpiration).Unix(),
		"iat": now.Unix(),
		"iss": "agentcube-router",
	}

	for k, v := range claims {
		tokenClaims[k] = v
	}

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, tokenClaims)
	return token.SignedString(j.privateKey)
}

func (j *JWTManager) generateKeyPair() (string, string) {
	privateKey, err := rsa.GenerateKey(strings.NewReader(""), rsaKeySize)
	if err != nil {
		return "", ""
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	publicKeyBytes, err := x509.MarshalPKIXPublicKey(&privateKey.PublicKey)
	if err != nil {
		return string(privateKeyPEM), ""
	}

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "PUBLIC KEY",
		Bytes: publicKeyBytes,
	})

	return string(privateKeyPEM), string(publicKeyPEM)
}

func (j *JWTManager) loadPrivateKeyPEM(pemData string) error {
	block, _ := pem.Decode([]byte(pemData))
	if block == nil {
		return fmt.Errorf("failed to decode PEM block")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(block.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	j.privateKey = privateKey
	j.publicKey = &privateKey.PublicKey
	return nil
}

func NewSessionManager(storeClient store.Store) (SessionManager, error) {
	workloadMgrAddr := os.Getenv("WORKLOAD_MANAGER_URL")
	if workloadMgrAddr == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	httpClient := &http.Client{
		Timeout: 2 * time.Minute,
		Transport: &http.Transport{
			MaxIdleConnsPerHost: 100,
			DisableCompression:  false,
		},
	}

	transport, ok := httpClient.Transport.(*http.Transport)
	if !ok {
		return nil, fmt.Errorf("failed to assert transport type")
	}
	if err := http2.ConfigureTransport(transport); err != nil {
		return nil, fmt.Errorf("failed to configure HTTP/2 transport: %w", err)
	}

	return &manager{
		storeClient:     storeClient,
		workloadMgrAddr: workloadMgrAddr,
		httpClient:      httpClient,
	}, nil
}

func (m *manager) GetSandboxBySession(ctx context.Context, sessionID string, namespace string, name string, kind string) (*types.SandboxInfo, error) {
	if sessionID != "" {
		sandbox, err := m.storeClient.GetSandboxBySessionID(ctx, sessionID)
		if err == store.ErrNotFound {
			return nil, api.NewSessionNotFoundError(sessionID)
		}
		if err != nil {
			return nil, fmt.Errorf("failed to get sandbox from store: %w", err)
		}
		return sandbox, nil
	}

	req := api.CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}

	var endpoint string
	if kind == "CodeInterpreter" {
		endpoint = fmt.Sprintf("%s/v1/code-interpreter", m.workloadMgrAddr)
	} else {
		endpoint = fmt.Sprintf("%s/v1/agent-runtime", m.workloadMgrAddr)
	}

	body, err := json.Marshal(req)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal request: %w", err)
	}

	httpReq, err := http.NewRequestWithContext(ctx, "POST", endpoint, strings.NewReader(string(body)))
	if err != nil {
		return nil, fmt.Errorf("failed to create request: %w", err)
	}

	httpReq.Header.Set("Content-Type", "application/json")

	token := m.loadWorkloadManagerAuthToken()
	if token != "" {
		httpReq.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
	}

	resp, err := m.httpClient.Do(httpReq)
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}
	defer resp.Body.Close()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("failed to read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		if resp.StatusCode == http.StatusNotFound {
			return nil, api.NewSandboxTemplateNotFoundError(namespace, name, kind)
		}
		return nil, fmt.Errorf("workload manager returned status %d: %s", resp.StatusCode, string(respBody))
	}

	var createResp api.CreateSandboxResponse
	if err := json.Unmarshal(respBody, &createResp); err != nil {
		return nil, fmt.Errorf("failed to unmarshal response: %w", err)
	}

	if createResp.SessionID == "" {
		return nil, fmt.Errorf("workload manager returned empty session ID")
	}

	sandboxInfo := &types.SandboxInfo{
		SessionID:   createResp.SessionID,
		SandboxID:   createResp.SandboxID,
		Name:        createResp.SandboxName,
		Namespace:   namespace,
		Kind:        kind,
		EntryPoints: createResp.EntryPoints,
		CreatedAt:   time.Now(),
		ExpiresAt:   time.Now().Add(15 * time.Minute),
	}

	if err := m.storeClient.StoreSandbox(ctx, sandboxInfo); err != nil {
		return nil, fmt.Errorf("failed to store sandbox: %w", err)
	}

	return sandboxInfo, nil
}

func (m *manager) loadWorkloadManagerAuthToken() string {
	tokenPath := "/var/run/secrets/kubernetes.io/serviceaccount/token"
	data, err := os.ReadFile(tokenPath)
	if err != nil {
		if !os.IsNotExist(err) {
			fmt.Fprintf(os.Stderr, "Warning: failed to read service account token: %v\n", err)
		}
		return ""
	}
	return strings.TrimSpace(string(data))
}

func (s *Server) setupRoutes() {
	s.engine.GET("/health/live", s.handleHealthLive)
	s.engine.GET("/health/ready", s.handleHealthReady)

	v1 := s.engine.Group("/v1")
	v1.Use(gin.Logger())
	v1.Use(gin.Recovery())
	v1.Use(s.concurrencyLimitMiddleware())

	v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)
	v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", s.handleAgentInvoke)

	v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
	v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", s.handleCodeInterpreterInvoke)
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (s *Server) concurrencyLimitMiddleware() gin.HandlerFunc {
	limit := s.config.MaxConcurrentRequests
	if limit <= 0 {
		limit = 1000
	}

	sem := make(chan struct{}, limit)

	return func(c *gin.Context) {
		select {
		case sem <- struct{}{}:
			defer func() { <-sem }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

func (s *Server) handleAgentInvoke(c *gin.Context) {
	s.handleInvoke(c, types.AgentRuntimeKind)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	s.handleInvoke(c, types.CodeInterpreterKind)
}

func (s *Server) handleInvoke(c *gin.Context, kind string) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")
	sessionID := c.GetHeader("x-agentcube-session-id")

	ctx := c.Request.Context()

	sandbox, err := s.sessionManager.GetSandboxBySession(ctx, sessionID, namespace, name, kind)
	if err != nil {
		s.handleGetSandboxError(c, err)
		return
	}

	if err := s.storeClient.UpdateSessionLastActivity(ctx, sandbox.SessionID, time.Now()); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: failed to update last activity: %v\n", err)
	}

	upstreamURL, err := s.determineUpstreamURL(sandbox, path)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(upstreamURL)
	proxy.Transport = s.httpTransport
	proxy.ErrorHandler = s.proxyErrorHandler
	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = upstreamURL.Scheme
		req.URL.Host = upstreamURL.Host
		req.URL.Path = s.normalizePath(path)
		req.URL.RawPath = ""
		req.Host = upstreamURL.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		if xff := req.Header.Get("X-Forwarded-For"); xff != "" {
			req.Header.Set("X-Forwarded-For", xff+", "+c.ClientIP())
		} else {
			req.Header.Set("X-Forwarded-For", c.ClientIP())
		}

		if kind == types.SandboxKind || kind == types.SandboxClaimsKind {
			claims := map[string]interface{}{
				"session_id": sandbox.SessionID,
			}
			token, err := s.jwtManager.GenerateToken(claims)
			if err != nil {
				fmt.Fprintf(os.Stderr, "Warning: failed to generate JWT: %v\n", err)
				return
			}
			req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sandbox.SessionID)
		return nil
	}

	proxy.ServeHTTP(c.Writer, c.Request)

	if err := s.storeClient.UpdateSessionLastActivity(ctx, sandbox.SessionID, time.Now()); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: failed to update last activity: %v\n", err)
	}
}

func (s *Server) determineUpstreamURL(sandbox *types.SandboxInfo, path string) (*url.URL, error) {
	if len(sandbox.EntryPoints) == 0 {
		return nil, fmt.Errorf("no entry point found for sandbox")
	}

	var matchedEntry *types.SandboxEntryPoint
	for i, ep := range sandbox.EntryPoints {
		if strings.HasPrefix(path, ep.Path) {
			matchedEntry = &sandbox.EntryPoints[i]
			break
		}
	}

	if matchedEntry == nil {
		matchedEntry = &sandbox.EntryPoints[0]
	}

	endpoint := matchedEntry.Endpoint
	if matchedEntry.Protocol != "" && !strings.HasPrefix(endpoint, "http://") && !strings.HasPrefix(endpoint, "https://") {
		endpoint = fmt.Sprintf("%s://%s", strings.ToLower(string(matchedEntry.Protocol)), endpoint)
	}

	return url.Parse(endpoint)
}

func (s *Server) normalizePath(path string) string {
	if path == "" {
		return "/"
	}
	if !strings.HasPrefix(path, "/") {
		return "/" + path
	}
	return path
}

func (s *Server) proxyErrorHandler(w http.ResponseWriter, r *http.Request, err error) {
	errMsg := err.Error()
	if strings.Contains(errMsg, "connection refused") || strings.Contains(errMsg, "no such host") {
		w.WriteHeader(http.StatusBadGateway)
		w.Write([]byte(`{"error":"sandbox unreachable"}`))
	} else if strings.Contains(errMsg, "timeout") || strings.Contains(errMsg, "deadline exceeded") {
		w.WriteHeader(http.StatusGatewayTimeout)
		w.Write([]byte(`{"error":"sandbox timeout"}`))
	} else {
		w.WriteHeader(http.StatusBadGateway)
		w.Write([]byte(`{"error":"sandbox unreachable"}`))
	}
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	if apiErr, ok := err.(apierrors.APIStatus); ok {
		status := apiErr.Status()
		code := int(status.Code)
		if code == 0 {
			code = http.StatusInternalServerError
		}
		message := status.Message
		if message == "" {
			message = err.Error()
		}
		if code == http.StatusInternalServerError {
			message = "internal server error"
		}
		c.JSON(code, gin.H{"error": message})
		return
	}
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (s *Server) Start() error {
	addr := ":" + s.config.Port

	s.httpServer = &http.Server{
		Addr:              addr,
		Handler:           h2c.NewHandler(s.engine, &http2.Server{}),
		ReadTimeout:       30 * time.Second,
		IdleTimeout:       90 * time.Second,
		ReadHeaderTimeout: 10 * time.Second,
	}

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return fmt.Errorf("TLS is enabled but cert or key path not provided")
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	var shutdownErr error
	var wg sync.WaitGroup

	wg.Add(1)
	go func() {
		defer wg.Done()
		shutdownErr = s.httpServer.Shutdown(ctx)
	}()

	wg.Wait()
	return shutdownErr
}

