	// Ping store
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	if err := storage.Ping(ctx); err != nil {
		klog.Fatalf("Failed to ping store: %v", err)
	}

	// Create Kubernetes client
	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Fatalf("Failed to get in-cluster config: %v", err)
	}

	dynamicClient, err := dynamic.NewForConfig(config)
	if err != nil {
		klog.Fatalf("Failed to create dynamic client: %v", err)
	}

	// Create HTTP server
	engine := gin.New()
	engine.Use(gin.Recovery())

	// Health endpoint
	engine.GET("/health", func(c *gin.Context) {
		c.JSON(http.StatusOK, gin.H{"status": "healthy"})
	})

	// V1 API routes with middleware
	v1 := engine.Group("/v1")
	v1.Use(loggingMiddleware())
	if enableAuth {
		v1.Use(authMiddleware())
	}

	// Agent runtime routes
	v1.POST("/agent-runtime", createSandboxHandler(dynamicClient, storage, "AgentRuntime"))
	v1.DELETE("/agent-runtime/sessions/:sessionId", deleteSessionHandler(dynamicClient, storage))

	// Code interpreter routes
	v1.POST("/code-interpreter", createSandboxHandler(dynamicClient, storage, "CodeInterpreter"))
	v1.DELETE("/code-interpreter/sessions/:sessionId", deleteSessionHandler(dynamicClient, storage))

	// Start garbage collection
	go startGarbageCollector(storage, dynamicClient, config)

	// Create HTTP server
	server := &http.Server{
		Addr:              ":" + port,
		Handler:           h2c.NewHandler(engine, &http2.Server{}),
		ReadTimeout:       DefaultReadTimeout,
		IdleTimeout:       DefaultIdleTimeout,
		ReadHeaderTimeout: 10 * time.Second,
	}

	// Start server in goroutine
	go func() {
		klog.Infof("Starting workload manager on port %s", port)
		if err := server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
