func createSandboxHandler(dynamicClient dynamic.Interface, storage store.Store, kind string) gin.HandlerFunc {
	return func(c *gin.Context) {
		var req api.CreateSandboxRequest
		if err := c.ShouldBindJSON(&req); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"message": "Invalid request body"})
			return
		}

		req.Kind = kind
		if err := req.Validate(); err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"message": err.Error()})
			return
		}

		ctx := c.Request.Context()

		// Create sandbox via dynamic client
		var gvr schema.GroupVersionResource
		if kind == "CodeInterpreter" {
			gvr = v1alpha1.SchemeGroupVersion.WithResource("codeinterpreters")
		} else {
			gvr = v1alpha1.SchemeGroupVersion.WithResource("agentruntimes")
		}

		// Store placeholder
		sessionID := generateSessionID()
		sandboxInfo := &store.SandboxInfo{
			SessionID: sessionID,
			Name:      req.Name,
			Namespace: req.Namespace,
			Kind:      kind,
			CreatedAt: time.Now(),
			ExpiresAt: time.Now().Add(DefaultSandboxIdleTimeout),
		}

		if err := storage.StoreSandbox(ctx, sandboxInfo); err != nil {
			klog.Errorf("Failed to store sandbox: %v", err)
			c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
			return
		}

		// TODO: Actually create sandbox resource in Kubernetes
		// This is a simplified implementation

		c.JSON(http.StatusOK, api.CreateSandboxResponse{
			SessionID:   sessionID,
			SandboxID:   sessionID,
			SandboxName: req.Name,
			EntryPoints: []api.EntryPoint{},
		})
	}
}

func deleteSessionHandler(dynamicClient dynamic.Interface, storage store.Store) gin.HandlerFunc {
	return func(c *gin.Context) {
		sessionID := c.Param("sessionId")
		if sessionID == "" {
			c.JSON(http.StatusBadRequest, gin.H{"message": "session ID is required"})
			return
		}

		ctx := c.Request.Context()

		// Load sandbox from store
		sandbox, err := storage.GetSandboxBySessionID(ctx, sessionID)
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, gin.H{"message": "Session ID " + sessionID + " not found, maybe already deleted"})
			return
		}
		if err != nil {
			klog.Errorf("Failed to get sandbox: %v", err)
			c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
			return
		}

		// TODO: Delete actual Kubernetes resources

		// Delete from store
		if err := storage.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
			klog.Errorf("Failed to delete sandbox from store: %v", err)
		}

		c.JSON(http.StatusOK, gin.H{"message": "Sandbox deleted successfully"})
	}
}

func loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		c.Next()
		klog.Infof("%s %s %d %v", c.Request.Method, c.Request.URL.Path, c.Writer.Status(), time.Since(start))
	}
}

func authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		auth := c.GetHeader("Authorization")
		if auth == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"message": "Missing authorization header"})
			c.Abort()
			return
		}

		// TODO: Implement proper TokenReview validation
		c.Next()
	}
}

func startGarbageCollector(storage store.Store, dynamicClient dynamic.Interface, config *rest.Config) {
	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		ctx, cancel := context.WithTimeout(context.Background(), 2*time.Minute)
		defer cancel()

		now := time.Now()
		inactiveTime := now.Add(-DefaultSandboxIdleTimeout)

		// List expired sessions
		expired, err := storage.ListExpiredSandboxes(ctx, now, 16)
		if err != nil {
			klog.Errorf("Failed to list expired sandboxes: %v", err)
			continue
		}

		// List inactive sessions
		inactive, err := storage.ListInactiveSandboxes(ctx, inactiveTime, 16)
		if err != nil {
			klog.Errorf("Failed to list inactive sandboxes: %v", err)
			continue
		}

		// Merge and deduplicate
		allSessionIDs := make(map[string]bool)
		for _, id := range expired {
			allSessionIDs[id] = true
		}
		for _, id := range inactive {
			allSessionIDs[id] = true
		}

		// Delete each sandbox
		for sessionID := range allSessionIDs {
			sandbox, err := storage.GetSandboxBySessionID(ctx, sessionID)
			if err == store.ErrNotFound {
				continue
			}
			if err != nil {
				klog.Errorf("Failed to get sandbox %s: %v", sessionID, err)
				continue
			}

			// TODO: Delete actual Kubernetes resources

			if err := storage.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
				klog.Errorf("Failed to delete sandbox %s: %v", sessionID, err)
			}
		}
	}
}

func generateSessionID() string {
	return uuid.New().String()
}

